window._isGlyphSupported = function(fontName, char) {
  const cov = window._FONT_COVERAGE[fontName];
  if (!cov) return true;
  if (cov === null) return true; // CJK-capable font, trust
  const cp = char.codePointAt(0);
  if (cp > 0xFFFF) return false; // supplementary planes: conservatively unsupported

  if (cov[0] === 1) {
    // BMP bitmap: O(1) bit lookup
    if (!cov._bmp) cov._bmp = Uint8Array.from(atob(cov[1]), c => c.charCodeAt(0));
    return (cov._bmp[cp >> 3] & (1 << (7 - (cp & 7)))) !== 0;
  }

  // Type 2: delta-encoded ranges → expand and binary search
  if (!cov._ranges) {
    const d = cov[1].split(',').map(Number);
    cov._ranges = [];
    let cur = d[0];
    cov._ranges.push([cur, cur + d[1]]);
    cur += d[1];
    for (let i = 2; i < d.length; i += 2) {
      cur += d[i];
      cov._ranges.push([cur, cur + d[i + 1]]);
      cur += d[i + 1];
    }
  }
  // Binary search
  let lo = 0, hi = cov._ranges.length - 1;
  while (lo <= hi) {
    const mid = (lo + hi) >> 1;
    const [s, e] = cov._ranges[mid];
    if (cp < s) hi = mid - 1;
    else if (cp > e) lo = mid + 1;
    else return true;
  }
  return false;
};